package main.rice.obj;

import java.util.*;

/**
 * Represents a Python list object.
 */
public class PyListObj<T extends APyObj> extends AIterablePyObj {

    private final List<T> value;

    /**
     * Construct a PyListObj with the given list of items.
     * @param items the list of items
     */
    public PyListObj(List<T> items) {
        this.value = new ArrayList<>(items);
    }

    /**
     * Get the underlying list of items.
     * @return the list of items
     */
    @Override
    public List<T> getValue() {
        return value;
    }

    /**
     * Return the Python-style string representation (elements in square brackets).
     * @return the string representation
     */
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("[");
        for (int i = 0; i < value.size(); i++) {
            if (i > 0) {
                sb.append(", ");
            }
            sb.append(value.get(i).toString());
        }
        sb.append("]");
        return sb.toString();
    }

    /**
     * Check equality with another object.
     * @param obj the object to compare with
     * @return true if obj is a PyListObj with the same value, false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof PyListObj)) {
            return false;
        }
        PyListObj<?> other = (PyListObj<?>) obj;
        return value.equals(other.value);
    }

    /**
     * Return a hash code for this object.
     * @return the hash code
     */
    @Override
    public int hashCode() {
        return value.hashCode();
    }
}

package main.rice.obj;

/**
 * Abstract base class for all Python objects.
 */
public abstract class APyObj {

    /**
     * Get the underlying Java value represented by this Python object.
     * @return the underlying value
     */
    public abstract Object getValue();

    /**
     * Return a string representation of this Python object.
     * @return the string representation
     */
    @Override
    public abstract String toString();

    /**
     * Check equality with another object.
     * Two APyObj instances are equal if they have the same type AND equal values.
     * @param obj the object to compare with
     * @return true if equal, false otherwise
     */
    @Override
    public abstract boolean equals(Object obj);

    /**
     * Return a hash code for this object.
     * @return the hash code
     */
    @Override
    public abstract int hashCode();
}

