import java.util.*;

/**
 * Represents a Python set object.
 */
public class PySetObj<T extends APyObj> extends AIterablePyObj {

    private final Set<T> value;

    /**
     * Construct a PySetObj with the given set of items.
     * @param items the set of items
     */
    public PySetObj(Set<T> items) {
        this.value = new LinkedHashSet<>(items);
    }

    /**
     * Get the underlying set of items.
     * @return the set of items
     */
    @Override
    public Set<T> getValue() {
        return value;
    }

    /**
     * Return the Python-style string representation (elements in curly braces).
     * Note: Python's empty set is set(), not {} (which is an empty dict).
     * @return the string representation
     */
    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "set()";
        }
        StringBuilder sb = new StringBuilder("{");
        boolean first = true;
        for (T item : value) {
            if (!first) {
                sb.append(", ");
            }
            sb.append(item.toString());
            first = false;
        }
        sb.append("}");
        return sb.toString();
    }

    /**
     * Check equality with another object.
     * @param obj the object to compare with
     * @return true if obj is a PySetObj with the same value, false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof PySetObj)) {
            return false;
        }
        PySetObj<?> other = (PySetObj<?>) obj;
        return value.equals(other.value);
    }

    /**
     * Return a hash code for this object.
     * @return the hash code
     */
    @Override
    public int hashCode() {
        return value.hashCode();
    }
}

