/**
 * Represents a Python tuple object.
 */
public class PyTupleObj<T extends APyObj> extends AIterablePyObj {

    private final List<T> value;

    /**
     * Construct a PyTupleObj with the given list of items.
     * @param items the list of items
     */
    public PyTupleObj(List<T> items) {
        this.value = new ArrayList<>(items);
    }

    /**
     * Get the underlying list of items.
     * @return the list of items
     */
    @Override
    public List<T> getValue() {
        return value;
    }

    /**
     * Return the Python-style string representation (elements in parentheses).
     * Note: Single-element tuples have a trailing comma: (1,)
     * @return the string representation
     */
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("(");
        for (int i = 0; i < value.size(); i++) {
            if (i > 0) {
                sb.append(", ");
            }
            sb.append(value.get(i).toString());
        }
        // Python single-element tuples have a trailing comma
        if (value.size() == 1) {
            sb.append(",");
        }
        sb.append(")");
        return sb.toString();
    }

    /**
     * Check equality with another object.
     * @param obj the object to compare with
     * @return true if obj is a PyTupleObj with the same value, false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof PyTupleObj)) {
            return false;
        }
        PyTupleObj<?> other = (PyTupleObj<?>) obj;
        return value.equals(other.value);
    }

    /**
     * Return a hash code for this object.
     * @return the hash code
     */
    @Override
    public int hashCode() {
        return value.hashCode();
    }
}

