import java.util.*;

/**
 * Represents a Python dictionary object.
 */
public class PyDictObj<K extends APyObj, V extends APyObj> extends AIterablePyObj {

    private final Map<K, V> value;

    /**
     * Construct a PyDictObj with the given map of key-value pairs.
     * @param items the map of key-value pairs
     */
    public PyDictObj(Map<K, V> items) {
        this.value = new LinkedHashMap<>(items);
    }

    /**
     * Get the underlying map of key-value pairs.
     * @return the map of key-value pairs
     */
    @Override
    public Map<K, V> getValue() {
        return value;
    }

    /**
     * Return the Python-style string representation (elements in curly braces with colons).
     * @return the string representation
     */
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("{");
        boolean first = true;
        for (Map.Entry<K, V> entry : value.entrySet()) {
            if (!first) {
                sb.append(", ");
            }
            sb.append(entry.getKey().toString())
              .append(": ")
              .append(entry.getValue().toString());
            first = false;
        }
        sb.append("}");
        return sb.toString();
    }

    /**
     * Check equality with another object.
     * @param obj the object to compare with
     * @return true if obj is a PyDictObj with the same value, false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof PyDictObj)) {
            return false;
        }
        PyDictObj<?, ?> other = (PyDictObj<?, ?>) obj;
        return value.equals(other.value);
    }

    /**
     * Return a hash code for this object.
     * @return the hash code
     */
    @Override
    public int hashCode() {
        return value.hashCode();
    }
}

